# Python Singleton Pattern dengan Metaclass untuk Configuration Storage

Berikut implementasi lengkap Singleton pattern menggunakan metaclass untuk penyimpanan konfigurasi global:

## Implementasi Dasar

```python
from typing import Any, Dict
from threading import Lock

class SingletonMeta(type):
    """Metaclass untuk menghasilkan Singleton thread-safe"""

    _instances: Dict[type, Any] = {}
    _lock: Lock = Lock()

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            with cls._lock:
                if cls not in cls._instances:
                    instance = super().__call__(*args, **kwargs)
                    cls._instances[cls] = instance
        return cls._instances[cls]


class ConfigManager(metaclass=SingletonMeta):
    """Global Configuration Storage dengan Singleton"""

    def __init__(self):
        if hasattr(self, '_initialized'):
            return
        self._config: Dict[str, Any] = {}
        self._initialized = True

    def set(self, key: str, value: Any) -> None:
        self._config[key] = value

    def get(self, key: str, default: Any = None) -> Any:
        return self._config.get(key, default)

    def delete(self, key: str) -> bool:
        if key in self._config:
            del self._config[key]
            return True
        return False

    def update(self, config_dict: Dict[str, Any]) -> None:
        self._config.update(config_dict)

    def clear(self) -> None:
        self._config.clear()

    def all(self) -> Dict[str, Any]:
        return self._config.copy()

    def __contains__(self, key: str) -> bool:
        return key in self._config

    def __repr__(self) -> str:
        return f"ConfigManager(keys={list(self._config.keys())})"
```

## Contoh Penggunaan

```python
# Inisialisasi
config = ConfigManager()

# Set konfigurasi
config.set('database.host', 'localhost')
config.set('database.port', 5432)
config.set('app.debug', True)

# Bulk update
config.update({
    'api.key': 'secret_key',
    'api.timeout': 30
})

# Get konfigurasi
db_host = config.get('database.host')
debug = config.get('app.debug', False)

# Cek keberadaan
if 'api.key' in config:
    print("API key configured")

# Instance kedua akan merujuk ke objek yang sama
config2 = ConfigManager()
assert config is config2  # True
```

## Versi dengan Validasi & Environment Support

```python
import os
from datetime import datetime

class SecureConfigManager(metaclass=SingletonMeta):
    """Singleton Config dengan validasi dan environment support"""

    def __init__(self):
        if hasattr(self, '_initialized'):
            return

        self._config: Dict[str, Any] = {}
        self._schema: Dict[str, type] = {}
        self._readonly: set = set()
        self._audit_log: list = []
        self._initialized = True

    def register_schema(self, key: str, dtype: type, readonly: bool = False) -> None:
        self._schema[key] = dtype
        if readonly:
            self._readonly.add(key)

    def set(self, key: str, value: Any) -> None:
        if key in self._readonly and key in self._config:
            raise ValueError(f"Key '{key}' is readonly")

        if key in self._schema:
            if not isinstance(value, self._schema[key]):
                raise TypeError(f"Expected {self._schema[key].__name__}, got {type(value).__name__}")

        self._config[key] = value
        self._log_audit('SET', key)

    def get(self, key: str, default: Any = None) -> Any:
        self._log_audit('GET', key)
        return self._config.get(key, default)

    def load_from_env(self, prefix: str = '') -> None:
        for key, dtype in self._schema.items():
            env_key = f"{prefix}{key.upper().replace('.', '_')}"
            value = os.getenv(env_key)
            if value:
                if dtype == bool:
                    value = value.lower() in ('true', '1', 'yes')
                elif dtype == int:
                    value = int(value)
                elif dtype == float:
                    value = float(value)
                self.set(key, value)

    def _log_audit(self, action: str, key: str) -> None:
        self._audit_log.append({
            'timestamp': datetime.now().isoformat(),
            'action': action,
            'key': key
        })

    def get_audit_log(self) -> list:
        return self._audit_log.copy()
```

## Testing

```python
def test_singleton():
    config1 = ConfigManager()
    config2 = ConfigManager()

    assert config1 is config2, "Singleton failed"

    config1.set('test', 'value')
    assert config2.get('test') == 'value', "State not shared"

    print("✓ Singleton test passed")

def test_thread_safety():
    import threading

    instances = []

    def create_instance():
        instances.append(ConfigManager())

    threads = [threading.Thread(target=create_instance) for _ in range(100)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    assert all(i is instances[0] for i in instances), "Thread safety failed"
    print("✓ Thread safety test passed")

if __name__ == '__main__':
    test_singleton()
    test_thread_safety()
```

## Security Notes

| Aspek | Implementasi |
|-------|-------------|
| **Thread Safety** | Double-check locking dengan `threading.Lock` |
| **Validation** | Schema validation untuk type checking |
| **Audit Trail** | Logging semua akses konfigurasi |
| **Readonly Keys** | Prevent modifikasi critical config |
| **Environment** | Support load dari environment variables |

## Best Practices

1. **Jangan store sensitive data** (password, API keys) dalam plain text
2. **Gunakan environment variables** untuk production secrets
3. **Enable audit logging** untuk compliance
4. **Implement encryption** untuk config sensitif
5. **Validate input** sebelum set konfigurasi

Implementasi ini production-ready untuk global configuration storage dengan keamanan dan thread-safety yang terjamin.
